import React, { useState } from "react";
import { 
  Card, 
  Typography, 
  Space, 
  Button, 
  Table, 
  Tag, 
  theme,
  Row,
  Col,
  Input,
  message,
  Popconfirm,
  Avatar,
  Modal,
  Form
} from "antd";
import { 
  SearchOutlined, 
  PlusOutlined,
  DeleteOutlined,
  EditOutlined,
  DatabaseOutlined,
  EnvironmentOutlined,
  ExportOutlined,
  GlobalOutlined,
  QrcodeOutlined
} from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { mockStorages, StorageInfo } from "../../dashboard/data/mockData";
import { exportToExcel } from "../../../utils/exportExcel";

const { Title, Text } = Typography;

export default function StorageManagePage() {
  const { token } = theme.useToken();
  const { t } = useI18n(["storageLocker", "platform", "common"]);
  const [searchText, setSearchText] = useState("");
  const [data, setData] = useState<StorageInfo[]>(mockStorages);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<StorageInfo | null>(null);
  const [form] = Form.useForm();

  const showModal = (record?: StorageInfo) => {
    if (record) {
      setEditingItem(record);
      form.setFieldsValue(record);
    } else {
      setEditingItem(null);
      form.resetFields();
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    form.validateFields().then(values => {
      if (editingItem) {
        // Edit Logic
        setData(data.map(item => item.id === editingItem.id ? { ...item, ...values } : item));
        message.success(`${t("common:edit")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
      } else {
        // Add Logic
        const newItem: StorageInfo = {
          ...values,
          id: values.id || `SL-${Date.now()}`, // Generate if missing
          temperature: 0,
          humidity: 0,
          connectState: "off"
        };
        setData([newItem, ...data]);
        message.success(`${t("common:add")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
      }
      setIsModalOpen(false);
    });
  };

  const handleDelete = (id: string) => {
    setData(data.filter(item => item.id !== id));
    message.success(t("common:delete_success"));
  };

  const columns = [
    {
      title: t("storageLocker:dashboard.lockerName"),
      dataIndex: "name",
      key: "name",
      render: (text: string) => (
        <Space>
          <Avatar icon={<DatabaseOutlined />} style={{ backgroundColor: token.colorPrimaryBg, color: token.colorPrimary }} />
          <Text strong>{text}</Text>
        </Space>
      ),
    },
    {
      title: t("storageLocker:dashboard.lockerId"),
      dataIndex: "id",
      key: "id",
      render: (text: string) => <Tag color="orange" icon={<QrcodeOutlined />}>{text}</Tag>,
    },
    {
      title: t("storageLocker:dashboard.address"),
      dataIndex: "address",
      key: "address",
      render: (text: string) => (
        <Space size="small">
          <EnvironmentOutlined style={{ color: token.colorTextSecondary }} />
          <span>{text}</span>
        </Space>
      ),
      ellipsis: true,
    },
    {
      title: t("storageLocker:dashboard.ipAddress"),
      key: "ipAddress",
      render: (record: any) => <Text code>{record.ip || "192.168.10.1"}</Text>,
    },
    {
      title: t("storageLocker:dashboard.status"),
      dataIndex: "connectState",
      key: "connectState",
      render: (state: string) => (
        <Tag color={state === "on" ? "success" : "error"}>
          {state === "on" ? t("storageLocker:dashboard.on") : t("storageLocker:dashboard.off")}
        </Tag>
      ),
    },
    {
      title: t("common:action"),
      key: "action",
      render: (_: any, record: StorageInfo) => (
        <Space size="middle">
          <Button type="link" size="small" icon={<EditOutlined />} onClick={() => showModal(record)}>
            {t("common:edit")}
          </Button>
          <Popconfirm title={t("common:confirm_delete")} onConfirm={() => handleDelete(record.id)}>
            <Button type="link" size="small" danger icon={<DeleteOutlined />}>
              {t("common:delete")}
            </Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  const filteredData = data.filter(item => 
    item.name.toLowerCase().includes(searchText.toLowerCase()) ||
    item.address.toLowerCase().includes(searchText.toLowerCase())
  );

  const handleExportXlsx = async () => {
    const success = await exportToExcel(data, "Locker_Management_List");
    if (success) {
      message.success(`${t("common:exportXlsx")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
    }
  };

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24, height: "100%", overflow: "auto" }}>
      {/* Header & Control Bar */}
      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Row gutter={[24, 16]} align="middle">
          <Col xs={24} md={8}>
            <Title level={4} style={{ margin: 0 }}>
              <DatabaseOutlined style={{ marginRight: 8, color: token.colorPrimary }} />
              {t("storageLocker:navigation.manageStorage")}
            </Title>
          </Col>
          <Col xs={24} md={16} style={{ textAlign: "right" }}>
            <Space size="middle">
              <Input 
                placeholder={t("common:search")} 
                prefix={<SearchOutlined />} 
                style={{ width: 300 }}
                onChange={e => setSearchText(e.target.value)}
                allowClear
              />
              <Button type="primary" icon={<PlusOutlined />} onClick={() => showModal()}>
                {t("common:add")}
              </Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* Main Grid */}
      <Card bordered={false} bodyStyle={{ padding: 0 }} style={{ flex: 1, boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Table 
          columns={columns} 
          dataSource={filteredData} 
          rowKey="id"
          pagination={{ pageSize: 12 }}
          scroll={{ y: "calc(100vh - 400px)" }}
        />
      </Card>

      <div style={{ textAlign: "left", paddingLeft: 8 }}>
        <Space style={{ width: "100%", justifyContent: "space-between" }}>
          <Text type="secondary">
            <DatabaseOutlined style={{ marginRight: 4 }} />
            {t("common:total")}: {filteredData.length} {t("storageLocker:dashboard.unit_ea")}
          </Text>
          <Button icon={<ExportOutlined />} onClick={handleExportXlsx}>
            {t("common:exportXlsx")}
          </Button>
        </Space>
      </div>

      {/* Locker Add/Edit Modal */}
      <Modal
        title={editingItem ? `${t("common:edit")} ${t("storageLocker:navigation.manageStorage")}` : `${t("common:add")} ${t("storageLocker:navigation.manageStorage")}`}
        open={isModalOpen}
        onOk={handleSave}
        onCancel={() => setIsModalOpen(false)}
        destroyOnClose
      >
        <Form form={form} layout="vertical" style={{ marginTop: 16 }}>
          <Form.Item name="name" label={t("storageLocker:dashboard.lockerName")} rules={[{ required: true }]}>
            <Input />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="id" label={t("storageLocker:dashboard.lockerId")} rules={[{ required: true }]}>
                <Input prefix={<QrcodeOutlined />} placeholder="SL-XXX" disabled={!!editingItem} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="ip" label={t("storageLocker:dashboard.ipAddress")} initialValue="192.168.10.1">
                <Input placeholder="192.168.x.x" />
              </Form.Item>
            </Col>
          </Row>

          <Form.Item name="address" label={t("storageLocker:dashboard.address")} rules={[{ required: true }]}>
            <Input prefix={<EnvironmentOutlined />} />
          </Form.Item>

          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="lat" label={t("storageLocker:dashboard.latitude")} initialValue={35.539}>
                <Input prefix={<GlobalOutlined />} type="number" step="0.001" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="lng" label={t("storageLocker:dashboard.longitude")} initialValue={129.311}>
                <Input prefix={<GlobalOutlined />} type="number" step="0.001" />
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Modal>
    </div>
  );
}
